<?php require_once __DIR__.'/../config/db.php'; require_once __DIR__.'/../includes/csrf.php'; $title='Catalogue voitures de location au Maroc | Atlas Drive System'; $description='Comparez les voitures disponibles au Maroc.'; $where=['status != :h'];$p=['h'=>'hidden'];foreach(['category','transmission','fuel_type'] as $f){if(trim($_GET[$f]??'')!==''){$where[]="$f = :$f";$p[$f]=trim($_GET[$f]);}}$st=$pdo->prepare('SELECT * FROM cars WHERE '.implode(' AND ',$where).' ORDER BY price_per_day ASC');$st->execute($p);$cars=$st->fetchAll();include __DIR__.'/../includes/header.php';?><section class="page-hero"><h1>Voitures de location au Maroc</h1><p>Filtrez par catégorie, transmission, carburant et ville de prise en charge.</p></section><form class="filters"><select name="category"><option value="">Catégorie</option><option>Economique</option><option>Compacte</option><option>SUV</option><option>Luxe</option></select><select name="transmission"><option value="">Transmission</option><option>Manuelle</option><option>Automatique</option></select><select name="fuel_type"><option value="">Carburant</option><option>Diesel</option><option>Essence</option></select><input name="city" placeholder="Ville"><button class="btn primary">Filtrer</button></form><section class="section"><div class="car-grid"><?php foreach($cars as $car) include __DIR__.'/../partials_car_card.php';?></div><?php if(!$cars):?><p class="empty">Aucun véhicule ne correspond. Essayez un autre filtre ou contactez-nous sur WhatsApp.</p><?php endif;?></section><?php include __DIR__.'/../includes/footer.php';?>